import copy
import json

def apply_patch(document, patches):
    """Apply a list of JSON Patch operations (RFC 6902 subset) to a document.
    Supports: add, remove, replace operations.
    Path format: '/key/index/nested' (JSON Pointer, RFC 6901)
    Returns the modified document.
    """
    result = copy.deepcopy(document)

    def unescape_json_pointer(s):
        """Unescape JSON Pointer reference token per RFC 6901."""
        return s.replace('~1', '/').replace('~0', '~')

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Handle empty path (refers to whole document)
        if path == '':
            if op == 'add' or op == 'replace':
                result = value
            elif op == 'remove':
                result = None
            continue

        # Parse JSON pointer
        if not path.startswith('/'):
            raise ValueError(f"Invalid JSON Pointer: {path}")

        parts = path[1:].split('/')  # Remove leading '/' and split
        parts = [unescape_json_pointer(part) for part in parts]

        # Navigate to parent
        parent = result
        for part in parts[:-1]:
            if isinstance(parent, list):
                parent = parent[int(part)]
            else:
                parent = parent[part]

        target = parts[-1]

        if op == 'add':
            if isinstance(parent, list):
                if target == '-':
                    parent.append(value)
                else:
                    parent.insert(int(target), value)
            else:
                parent[target] = value

        elif op == 'remove':
            if isinstance(parent, list):
                del parent[int(target)]
            else:
                del parent[target]

        elif op == 'replace':
            if isinstance(parent, list):
                parent[int(target)] = value
            else:
                parent[target] = value

    return result

