            return dt.utctimetuple()
        else:
            # Keep naive datetime as is for comparison
            return dt.timetuple()

    # Actually, let's fix this properly by converting to UTC datetime objects
    def to_utc_datetime(dt):
        if dt.tzinfo is not None:
            # Convert to UTC and make naive
            return dt.utctimetuple()
        return dt.timetuple()

    # Better approach: convert everything to UTC datetime objects
    def normalize_to_utc(dt):
        if dt.tzinfo is not None:
            # Convert timezone-aware to UTC, then make naive
            utc_dt = dt.astimezone(timezone.utc)
            return utc_dt.replace(tzinfo=None)
        else:
            # Assume naive datetime is already in UTC
            return dt

