def apply_patch(document, patches):
    """Apply a list of JSON Patch operations (RFC 6902 subset) to a document.
    Supports: add, remove, replace operations.
    Path format: '/key/index/nested' (JSON Pointer, RFC 6901)
    Returns the modified document.
    """
    result = copy.deepcopy(document)

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Handle empty path (refers to whole document)
        if path == '':
            if op == 'replace':
                return value
            elif op == 'remove':
                return None
            elif op == 'add':
                return value
            continue

        # Parse JSON pointer with proper unescaping
        def unescape_json_pointer(token):
            return token.replace('~1', '/').replace('~0', '~')

        # Split path and handle root case
        if path == '/':
            parts = ['']
        else:
            parts = [unescape_json_pointer(part) for part in path[1:].split('/')]

        # Navigate to parent
        parent = result
        for part in parts[:-1]:
            if isinstance(parent, list):
                parent = parent[int(part)]
            else:
                parent = parent[part]

        target = parts[-1]

        if op == 'add':
            if isinstance(parent, list):
                if target == '-':
                    parent.append(value)
                else:
                    parent.insert(int(target), value)
            else:
                parent[target] = value

        elif op == 'remove':
            if isinstance(parent, list):
                del parent[int(target)]
            else:
                del parent[target]

        elif op == 'replace':
            if isinstance(parent, list):
                parent[int(target)] = value
            else:
                parent[target] = value

    return result

