    def __init__(self):
        self.children = {}
        self.is_end = False
        self._words = []  # Track all words for verification

    def insert(self, word):
        self._words.append(word)
        node = self
        for ch in word:
            if ch not in node.children:
                node.children[ch] = WildcardTrie()
            node = node.children[ch]
        node.is_end = True

    def search(self, pattern):
        """Search for pattern where '.' matches any character."""
        return self._search(self, pattern, 0)

    def _search(self, node, pattern, index):
        if index == len(pattern):
            return node.is_end

        ch = pattern[index]
        if ch == '.':
            # Try each child
            for child_key in list(node.children.keys()):
                if self._search(node.children[child_key], pattern, index + 1):
                    return True
            return False
        else:
            child = node.children.get(ch)
            if child is None:
                return False
            return self._search(child, pattern, index + 1)

    def get_all_words(self):
        """Return all inserted words."""
        return self._words[:]

    def starts_with(self, prefix):
        """Return True if any word starts with the given prefix."""
        node = self
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        # Check if there's any word that starts with this prefix
        return self._has_words_below(node)

    def _has_words_below(self, node):
        """Check if there are any complete words in the subtree rooted at node."""
        if node.is_end:
            return True
        for child in node.children.values():
            if self._has_words_below(child):
                return True
        return False

    def delete(self, word):
        """Delete a word from the trie."""
        if word in self._words:
            self._words.remove(word)
            self._delete(self, word, 0)

    def _delete(self, node, word, index):
        """Delete a word and return True if the current node should be deleted."""
        if index == len(word):
            node.is_end = False
            # Return True if this node has no children and is not end of another word
            return len(node.children) == 0 and not node.is_end

        ch = word[index]
        if ch not in node.children:
            return False  # Word doesn't exist

        should_delete_child = self._delete(node.children[ch], word, index + 1)

        if should_delete_child:
            del node.children[ch]

        # Return True if current node should be deleted
        # (has no children, is not end of word, and we're not at root)
        return len(node.children) == 0 and not node.is_end and node is not self

